class Solution(object):
    def colorTheArray(self, n, queries):
        colors = [0] * n
        count = 0
        ans = []

        for idx, color in queries:
            old = colors[idx]
            # Remove old adjacency contributions
            if old != 0:  # was colored
                if idx > 0 and colors[idx - 1] == old:
                    count -= 1
                if idx < n - 1 and colors[idx + 1] == old:
                    count -= 1
            # Apply new color
            colors[idx] = color
            # Add new adjacency contributions
            if idx > 0 and colors[idx - 1] == color:
                count += 1
            if idx < n - 1 and colors[idx + 1] == color:
                count += 1
            ans.append(count)

        return ans
